.aurora {
  background: conic-gradient(
    from 180deg at 50% 50%,
    #8A6F9B 0deg,
    #183153 90deg,
    #FF3B8D 180deg,
    #8A6F9B 360deg
  );
  filter: blur(40px);
  animation: flow 8s ease infinite;
}

