function isPrime(n) {
  for(let i = 2; i <= Math.sqrt(n); i++)
    if(n % i === 0) return false;
  return n > 1;
}

const grid = Array.from({length: 64}, (_, i) => ({
  active: isPrime(i + 1),
  opacity: (i % 7) / 7
}));

