const fetchFlights = async (bounds) => {
  const { lamin, lomin, lamax, lomax } = bounds;
  const res = await fetch(
    `https://opensky-network.org/api/states/all
    ?lamin=${lamin}&lomin=${lomin}
    &lamax=${lamax}&lomax=${lomax}`
  );
  return res.json();
};

